sql:
SELECT COUNT(DISTINCT transactions.user_id) AS unique_stars
FROM transactions
WHERE transactions.date >= DATE('now', '-30 day');

SELECT user_id, COUNT(wallet_id) AS Number_of_Wallets
FROM wallets
GROUP BY user_id;

SELECT crypto_name, symbol
FROM cryptocurrencies
ORDER BY creation_date;

SELECT user_name, email, password_hash
FROM users
WHERE user_id IN (SELECT DISTINCT user_id FROM transactions);

